import{_ as t,o as i,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"90. Staffing Anum Amum And Above","description":"","frontmatter":{"title":"90. Staffing Anum Amum And Above","eba":"Nurses and Midwives 2024-2028","topics":["wages","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/90-staffing-anum-amum-and-above.md","filePath":"ebas/nurses-midwives/classification-staffing/90-staffing-anum-amum-and-above.md"}'),r={name:"ebas/nurses-midwives/classification-staffing/90-staffing-anum-amum-and-above.md"};function o(s,e,p,d,g,l){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_90-staffing-anum-amum-and-above" tabindex="-1">90. Staffing Anum Amum And Above <a class="header-anchor" href="#_90-staffing-anum-amum-and-above" aria-label="Permalink to &quot;90. Staffing Anum Amum And Above&quot;">​</a></h1><p>Note: See <a href="/eba/ebas/nurses-midwives/allowances/35-higher-duties.html">clause 35</a> (Higher Duties) for any applicable payments related to performing higher duties under this clause.</p><p><strong>90.1A</strong> Registered Nurse – Nurse Unit Manager There must be:</p><p><strong>(a)</strong> one EFT Nurse Unit Manager appointed in each non maternity ward/unit of each Campus/facility of each hospital/network; or</p><p><strong>(b)</strong> two or more part-time Nurse Unit Managers may be appointed so long as one EFT of Nurse Unit Manager hours are worked in the shared position.</p><p><strong>(c)</strong> In the circumstances of a ward or unit that usually operates less than five days per week, there must be 0.1 EFT Nurse Unit Manager for each day of the fortnight that the ward or unit usually operates.</p><p><strong>90.1B</strong> Registered Midwife – Midwife Unit Manager There must be:</p><p><strong>(a)</strong> one EFT Midwife Unit Manager appointed in each maternity ward/unit of each Campus/facility of each hospital/network; or</p><p><strong>(b)</strong> two or more part-time Midwife Unit Managers may be appointed so long as one EFT of Midwife Unit Manager hours are worked in the shared position.</p><p><strong>(c)</strong> In the circumstances of a ward or unit that usually operates less than 5 days per week, there must be 0.2 EFT Midwife Unit Manager for each day of the week that the ward or unit usually operates.</p><p><strong>90.1C</strong> Maternity ward</p><p><strong>(a)</strong> Maternity includes ante-natal care, post-natal care and birthing suites.</p><p><strong>(b)</strong> A single ward that includes maternity services and non-maternity services is not required to have:</p><p><strong>(i)</strong> more than one EFT of combined NUM and MUM appointed; or</p><p><strong>(ii)</strong> more than the stated EFT of ANUM/AMUMs in clause 90.2 unless required by the Safe Patient Care Act.</p><p><strong>(c)</strong> Compliance with this provision constitutes compliance with clauses 90.1A and 90.1B.</p><p><strong>90.1D</strong> Safe Patient Care Act requiring additional Registered Nurse/Midwife in charge Note: This clause only operates if the Safe Patient Care Act mandates an additional Registered Nurse or Midwife in charge.</p><p><strong>(a)</strong> Nothing in this clause 90.1D detracts from the obligations in the Safe Patient Care Act in respect to ratios that require a nurse or midwife in charge, in addition to or as part of ratios.</p><p><strong>(b)</strong> Where the Safe Patient Care Act requires a ward/unit to have more than one Registered Nurse/Midwife in charge on a shift, the additional in-charge position will be classified as an ANUM/AMUM and be additional to the requirements in clause 90.2.</p><p><strong>90.2</strong> Associate Nurse/Midwife Unit Managers</p><p>ANUMs (or AMUMs in a Maternity Ward) are appointed to undertake in-charge functions during the off duty periods of the NUM/MUM. Except as set out in <a href="/eba/ebas/nurses-midwives/allowances/35-higher-duties.html">clause 35</a> (Higher Duties), the salary rate specified in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> of this Agreement includes the performance of the in-charge function during the off duty periods of the NUM/MUM.</p><p><strong>(a)</strong> 24 Hour a day, seven days per week wards/units</p><p>The following provisions apply to 24 hour a day, seven days per week wards/units.</p><p><strong>(i)</strong> There must be five EFT ANUM/AMUM shift positions available for appointment, and four out of the five positions must be permanently appointed.</p><p><strong>(ii)</strong> Nothing in any of these provisions prevents ANUM/AMUM positions being either full-time or part-time.</p><p><strong>(iii)</strong> The 5th EFT of ANUM/AMUM may be permanently appointed to, or may be utilised to provide non-appointed Registered Nurses and Registered Midwives with experience as an ANUM/AMUM.</p><p><strong>(iv)</strong> In exceptional circumstances, where a minimum of four EFT of ANUM/AMUMs are permanently appointed, a Registered Nurse or Registered Midwife other than an ANUM/AMUM may be required to act in charge during the off duty period of a NUM/MUM.</p><p><strong>(v)</strong> Where less than four EFT of ANUM/AMUMs are permanently appointed due to recruitment difficulties or delays or to circumstances beyond an Employer&#39;s control, a Registered Nurse or Midwife, other than an ANUM/AMUM, may be required to act in charge during the off duty period of a NUM/MUM (which event will be the exception to the rule).</p><p><strong>(vi)</strong> Where an Employer experiences difficulties in recruiting Employees to permanent ANUM/AMUM positions despite having taken reasonable and practical steps to fill the position(s), the Employer will contact the ANMF at the earliest opportunity. The ANMF and the Employer may then discuss and agree on alternative arrangements. Any agreement reached will be recorded in writing.</p><p><strong>(b)</strong> Non-24 hour a day, seven days per week wards or units</p><p>For wards or units which are not 24 hours a day, seven days per week, the Employer is to appoint an ANUM/AMUM to cover all off duty periods of the NUM/MUM. In exceptional circumstances, a Registered Nurse or Midwife who is not an appointed ANUM/AMUM may be required to act in charge during the off duty period of a NUM/MUM.</p><p><strong>90.3</strong> Registered Nurse – Director of Nursing</p><p>Despite any other provisions of this Agreement, each Employer must employ a full-time DON on each Campus, excluding community health centres.</p><p><strong>90.4</strong> Registered Nurse – After Hours Coordinator</p><p><strong>(a)</strong> A Registered Nurse who is an After Hours Coordinator as defined in the Safe Patient Care Act will be appointed to be in charge of each Campus in all off duty periods of the DON.</p><p><strong>(b)</strong> The indicative position description for an Employee appointed under subclause 90.4(a) is attached at <a href="/eba/ebas/nurses-midwives/appendices/05-indicative-position-description-for-after-hours-coordinator.html">Appendix 5</a> to this Agreement.</p><p><strong>90.5</strong> Registered Nurse – Clinical Liaison Nurse</p><p><strong>(a)</strong> Each Employer operating a Level 1 or a Level 2 Hospital (as defined in Schedule 1 of the Safe Patient Care Act) will have a minimum of one EFT of Clinical Liaison Nurse for each such hospital.</p><p><strong>(b)</strong> The aims of the position are to:</p><p><strong>(i)</strong> provide a consultation service for the management of behaviourally disturbed or compromised inpatients of the hospital with specific reference to inpatients requiring specialling;</p><p><strong>(ii)</strong> provide expert assessment and advise in the management of the behaviourally disturbed inpatient in relation to risk assessment;</p><p><strong>(iii)</strong> trial and implement strategies to ensure observation of patients is appropriate and ensures the most effective use of resources;</p><p><strong>(iv)</strong> assist acute health in the management of patients with behavioural disturbance;</p><p><strong>(v)</strong> assist and support staff in the development and implementation of behavioural nursing care plans;</p><p><strong>(vi)</strong> assist in the provision of nursing assessment and recommendations related to interventions for people with a mental illness who are receiving medical treatment;</p><p><strong>(vii)</strong> monitor and evaluate the quality of care provided by staff providing constant observation nurse;</p><p><strong>(viii)</strong> provide ongoing education and identify training needs in relation to the management of the behaviourally disturbed patient;</p><p><strong>(ix)</strong> evaluate current process of documentation and participate in the development and implementation of best practice documentation;</p><p><strong>(x)</strong> actively participate in any research or evaluation processes related to the target group;</p><p><strong>(xi)</strong> foster liaison with other Consultation Liaison services; and</p><p><strong>(xii)</strong> actively participate in related working parties and policy reviews.</p><p><strong>90A.1</strong> Senior Midwife</p><p><strong>(a)</strong> Each health service with a Level 4 or 5 Maternity Capability Framework maternity service (as defined in the Maternity Capability Framework as at 1 May 2024) must maintain at least 1 EFT of Senior Midwife.</p><p><strong>(b)</strong> If the DON is also a Midwife, the requirement at (a) may be met by allocating the role of Senior Midwife to the DON.</p><p><strong>(c)</strong> To ensure compliance with (a), the following Employers will appoint a Senior Midwife (however titled) by no later than 1 January 2025:</p><p><strong>(i)</strong> Mildura Public Hospital;</p><p><strong>(ii)</strong> West Gippsland Hospital; and</p><p><strong>(iii)</strong> Central Gippsland Health Service (Sale).</p><p><strong>90A.2</strong> Liaison Midwife</p><p><strong>(a)</strong> Within six months of the commencement of the Agreement, the Employers named at (c) below (each operating a capability level 4 or capability level 5 maternity service) will appoint and or maintain at least 1 EFT of Liaison Midwife.</p><p><strong>(b)</strong> The Employer will be the lead agency for the position of Liaison Midwife.</p><p><strong>(c)</strong> The Employers are:</p><p><strong>(i)</strong> Bendigo Health;</p><p><strong>(ii)</strong> Albury Wodonga Health;</p><p><strong>(iii)</strong> Barwon Health (University Campus);</p><p><strong>(iv)</strong> Grampians Health (Ballarat Campus);</p><p><strong>(v)</strong> Goulburn Valley (Shepparton Campus); and</p><p><strong>(vi)</strong> Latrobe Regional Hospital.</p>',68)])])}const c=t(r,[["render",o]]);export{u as __pageData,c as default};
